from flask import Flask, request, jsonify, redirect, url_for
import os
import secrets
import smtplib
from email.mime.text import MIMEText

app = Flask(__name__)
SECRET_KEY = 'your_secret_key'
MFA_USERS = {}

def send_email(email, link):
    sender_email = "no-reply@example.com"
    sender_password = "your-email-password"
    message = MIMEText(f"Click the following link to reset your MFA: {link}")
    message['Subject'] = 'Reset Your MFA'
    message['From'] = sender_email
    message['To'] = email

    with smtplib.SMTP('smtp.example.com', 587) as server:
        server.starttls()
        server.login(sender_email, sender_password)
        server.sendmail(sender_email, email, message.as_string())

@app.route('/enable-mfa')
def enable_mfa():
    email = request.args.get('email')
    if email in MFA_USERS:
        return jsonify({"error": "MFA is already enabled for this user."}), 400
    MFA_USERS[email] = {'enabled': True, 'reset_code': None}
    return jsonify({"message": "MFA has been enabled."})

@app.route('/disable-mfa')
def disable_mfa():
    email = request.args.get('email')
    if email not in MFA_USERS or not MFA_USERS[email]['enabled']:
        return jsonify({"error": "MFA is not enabled for this user."}), 400
    MFA_USERS[email]['enabled'] = False
    MFA_USERS[email]['reset_code'] = None
    return jsonify({"message": "MFA has been disabled."})

@app.route('/reset-mfa')
def reset_mfa():
    email = request.args.get('email')
    if email not in MFA_USERS:
        return jsonify({"error": "User not found."}), 404
    reset_code = secrets.token_urlsafe(16)
    MFA_USERS[email]['reset_code'] = reset_code
    reset_link = url_for('apply_reset', _external=True) + f'?email={email}&code={reset_code}'
    send_email(email, reset_link)
    return jsonify({"message": "Reset link has been sent to your email."})

@app.route('/apply-reset')
def apply_reset():
    email = request.args.get('email')
    code = request.args.get('code')
    if email not in MFA_USERS or MFA_USERS[email]['reset_code'] != code:
        return jsonify({"error": "Invalid reset link."}), 403
    MFA_USERS[email]['enabled'] = False
    MFA_USERS[email]['reset_code'] = None
    return redirect(url_for('login'))

